const file = $input.item.json;
const fileName = file.name || '';
const mimeType = file.mimeType || '';

const isPDF = fileName.toLowerCase().endsWith('.pdf') || mimeType === 'application/pdf';

return [{
  json: {
    ...file,
    fileId: file.id,
    fileName: file.name,
    isPDF: isPDF,
    submissionDate: new Date().toISOString()
  }
}];

const currentFile = $('Check File Is PDF1').item.json;
const fileId = currentFile.fileId;

// Get all rows from output sheet
const allRows = $input.all();

// If sheet is empty (first run), no duplicates possible
if (!allRows || allRows.length === 0) {
  return [{
    json: {
      ...currentFile,
      isDuplicateFile: false,
      isFirstRun: true
    }
  }];
}

// Check if file ID already exists
const isDuplicate = allRows.some(row => {
  const rowFileId = row.json['Resume File ID'] || '';
  return rowFileId === fileId;
});

return [{
  json: {
    ...currentFile,
    isDuplicateFile: isDuplicate,
    isFirstRun: false
  }
}];

const configRow = $input.first();
const fileData = $('Check File Duplicate1').item.json;

if (!configRow) {
  throw new Error('Config sheet is empty - please run sheet setup workflow first');
}

const config = configRow.json;

const readyToScore = (config.Ready_To_Score || '').toString().trim().toUpperCase();

// Parse and validate weights
const w1 = parseFloat(config.Weight_Skills_Match) || 0;
const w2 = parseFloat(config.Weight_Experience) || 0;
const w3 = parseFloat(config.Weight_Seniority) || 0;
const w4 = parseFloat(config.Weight_Impact_Quality) || 0;
const w5 = parseFloat(config.Weight_Red_Flag_Penalty) || 0;
const weightSum = w1 + w2 + w3 + w4 + w5;
const weightSumValid = Math.abs(weightSum - 100) < 0.01;

return [{
  json: {
    ...fileData,
    config: config,
    readyToScore: readyToScore,
    weightSum: weightSum,
    weights: { w1, w2, w3, w4, w5 },
    weightSumValid: weightSumValid,
    weightSumError: !weightSumValid
      ? `Weights sum to ${weightSum}, must equal 100`
      : ''
  }
}];

const allFiles = $input.all();

// Find first PDF in JD folder
const jdFile = allFiles.find(f => {
  const name = (f.json.name || '').toLowerCase();
  const mime = f.json.mimeType || '';
  return name.endsWith('.pdf') || mime === 'application/pdf';
});

if (!jdFile) {
  return [{
    json: {
      jdFound: false,
      jdError: 'No JD PDF found in JD folder'
    }
  }];
}

const jdFileId = jdFile.json.id;
const jdFileName = jdFile.json.name;
const jdModifiedTime = jdFile.json.modifiedTime || '';
const currentJDHash = `${jdFileId}_${jdModifiedTime}`;

return [{
  json: {
    jdFound: true,
    jdFileId,
    jdFileName,
    jdModifiedTime,
    currentJDHash
  }
}];

// The HTTP request node merges input json with response
// So $input.item.json has BOTH the Haiku response 
// AND the upstream data

const item = $input.item.json;

// Response is in item.content
// Upstream data is also on item directly
let jdAnalysis = null;

try {
  const content = item.content;
  let rawText = Array.isArray(content)
    ? content.filter(c => c.type === 'text').map(c => c.text).join('')
    : JSON.stringify(content);

  const cleaned = rawText
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  jdAnalysis = JSON.parse(cleaned);
} catch(e) {
  jdAnalysis = null;
}

if (!jdAnalysis) {
  return [{
    json: {
      jdQualityScore: 0,
      jdQualityBand: 'Poor',
      proceedWithScoring: false,
      config: item.config || {},
      weights: item.weights || {},
      jdFileName: item.jdFileName || '',
      currentJDHash: item.currentJDHash || '',
      jdModifiedTime: item.jdModifiedTime || ''
    }
  }];
}

const totalScore = jdAnalysis.total_score || 0;
let qualityBand = 'Poor';
if (totalScore >= 8) qualityBand = 'Strong';
else if (totalScore >= 5) qualityBand = 'Weak';

return [{
  json: {
    // Pass everything from upstream
    config: item.config || {},
    weights: item.weights || {},
    jdFileName: item.jdFileName || '',
    jdFileId: item.jdFileId || '',
    currentJDHash: item.currentJDHash || '',
    jdModifiedTime: item.jdModifiedTime || '',
    // JD analysis results
    jdAnalysis: jdAnalysis,
    jdQualityScore: totalScore,
    jdQualityBand: qualityBand,
    proceedWithScoring: totalScore >= 5,
    extractedRoleName: jdAnalysis.extracted_role_name || '',
    extractedSeniority: jdAnalysis.extracted_seniority || '',
    extractedExperience: jdAnalysis.extracted_experience || '',
    extractedIndustry: jdAnalysis.extracted_industry || '',
    extractedAdjacentIndustries: (jdAnalysis.extracted_adjacent_industries || []).join(', '),
    extractedResponsibilities: jdAnalysis.extracted_responsibilities || '',
    extractedMustHaveSkills: (jdAnalysis.extracted_must_have_skills || []).join(', '),
    extractedNiceToHaveSkills: (jdAnalysis.extracted_nice_to_have_skills || []).join(', '),
    absentFields: (jdAnalysis.absent_fields || []).join(', '),
    inferredFields: (jdAnalysis.inferred_fields || []).join(', ')
  }
}];

const items = $input.all();
const item = items[0];

// Text comes from Extract from File node
const rawText = item.json.text || '';

// Sanitize for JSON injection
const sanitized = rawText
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t')
  .replace(/[\x00-\x1F\x7F]/g, ' ');

// Pull context from upstream nodes using exact names
const configData = $('Parse Config1').item.json;
const jdFileData = $('Check JD File1').item.json;

return [{
  json: {
    jdTextSanitized: sanitized,
    jdWordCount: rawText.split(/\s+/).filter(w => w.length > 0).length,
    // Config context
    config: configData.config,
    weights: configData.weights,
    // JD file context
    jdFileName: jdFileData.jdFileName || '',
    jdFileId: jdFileData.jdFileId || '',
    currentJDHash: jdFileData.currentJDHash || '',
    jdModifiedTime: jdFileData.jdModifiedTime || ''
  }
}];

const items = $input.all();
const item = items[0].json;

const resumeText = item.resumeText || item.text || '';
const words = resumeText.split(/\s+/).filter(w => w.length > 0);
const wasTruncated = words.length > 3000;
const finalResumeText = wasTruncated 
  ? words.slice(0, 3000).join(' ')
  : resumeText;

const sanitized = finalResumeText
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t')
  .replace(/[\x00-\x1F\x7F]/g, ' ');

const wordCount = resumeText
  .split(/\s+/).filter(w => w.length > 0).length;
const nonAlphaRatio =
  (resumeText.replace(/[a-zA-Z0-9\s]/g, '').length) / (resumeText.length || 1);
const textLower = resumeText.toLowerCase();

const hasExperience = textLower.includes('experience')
  || textLower.includes('employment');
const hasSkills = textLower.includes('skills')
  || textLower.includes('technologies');
const hasEducation = textLower.includes('education')
  || textLower.includes('degree');
const sectionsFound = [hasExperience, hasSkills, hasEducation]
  .filter(Boolean).length;

let confidencePenalty = 0;
const confidenceSignals = [];

if (wordCount < 150) {
  confidencePenalty += 2;
  confidenceSignals.push('Resume under 150 words');
} else if (wordCount < 300) {
  confidencePenalty += 1;
  confidenceSignals.push('Resume under 300 words');
}
if (sectionsFound < 2) {
  confidencePenalty += 2;
  confidenceSignals.push(`Only ${sectionsFound} of 3 sections detected`);
} else if (sectionsFound < 3) {
  confidencePenalty += 1;
  confidenceSignals.push('One key section missing');
}
if (nonAlphaRatio > 0.3) {
  confidencePenalty += 2;
  confidenceSignals.push('High non-alphabetic character ratio');
}

const triggerData = $('Drive Trigger - New Resume1').item.json;

const scoringConfig = JSON.stringify({
  role: {
    title: item.extractedRoleName || '',
    seniority: item.extractedSeniority || '',
    experience_required: item.extractedExperience || '',
    experience_type: item.config?.Experience_Type || 'FULLTIME_ONLY', 
    industry: item.extractedIndustry || '',
    adjacent_industries: (item.extractedAdjacentIndustries || '')
      .split(',').map(s => s.trim()).filter(s => s),
    responsibilities: item.extractedResponsibilities || ''
  },
  skills: {
    must_have: (item.extractedMustHaveSkills || '')
      .split(',').map(s => s.trim()).filter(s => s),
    nice_to_have: (item.extractedNiceToHaveSkills || '')
      .split(',').map(s => s.trim()).filter(s => s)
  },
  scoring_context: {
    inferred_fields: (item.inferredFields || '')
      .split(',').map(s => s.trim()).filter(s => s),
    evaluation_date: new Date().toISOString().split('T')[0], 
    absent_fields: (item.absentFields || '')
      .split(',').map(s => s.trim()).filter(s => s)
  }
});
if (wasTruncated) {
  confidencePenalty += 1;
  confidenceSignals.push('Resume truncated at 3000 words — tail content not scored');
}

return [{
  json: {
    config: item.config || {},
    weights: item.weights || {},
    extractedRoleName: item.extractedRoleName || '',
    extractedSeniority: item.extractedSeniority || '',
    extractedExperience: item.extractedExperience || '',
    extractedIndustry: item.extractedIndustry || '',
    extractedAdjacentIndustries: item.extractedAdjacentIndustries || '',
    extractedResponsibilities: item.extractedResponsibilities || '',
    extractedMustHaveSkills: item.extractedMustHaveSkills || '',
    extractedNiceToHaveSkills: item.extractedNiceToHaveSkills || '',
    inferredFields: item.inferredFields || '',
    absentFields: item.absentFields || '',
    resumeTextSanitized: sanitized,
    resumeText: resumeText,
    resumeWordCount: wordCount,
    resumeExtractionFailed: wordCount < 150 || nonAlphaRatio > 0.3,
    resumeTruncated: wasTruncated,  // ← updated
    confidencePenaltyFromExtraction: confidencePenalty,
    confidenceSignals: confidenceSignals,
    sectionsFound: sectionsFound,
    fileId: triggerData.id || '',
    fileName: triggerData.name || '',
    submissionDate: new Date().toISOString(),
    scoringConfig: scoringConfig
  }
}];

