const item = $input.item.json;
const upstreamContext = $('Sanitize Resume1').item.json;

let candidateInfo = {
  name: '', email: '', mobile: '',
  current_title: '', total_years_experience: '',
  graduation_year: '', is_student: ''
};

try {
  const content = item.content;
  let rawText = Array.isArray(content)
    ? content.filter(c => c.type === 'text').map(c => c.text).join('')
    : JSON.stringify(content);
  const cleaned = rawText
    .replace(/```json/g, '').replace(/```/g, '').trim();
  candidateInfo = JSON.parse(cleaned);
} catch(e) {}

const rawId = `${candidateInfo.name || ''}_${candidateInfo.mobile || ''}`;
let hash = 0;
for (let i = 0; i < rawId.length; i++) {
  const char = rawId.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash = hash & hash;
}
const candidateId = Math.abs(hash).toString(16).toUpperCase().padStart(8, '0');

const dealbreakers = (upstreamContext.config?.Dealbreaker_Skills || '')
  .split(',').map(s => s.trim().toLowerCase()).filter(s => s.length > 0);
const resumeLower = (upstreamContext.resumeText || '').toLowerCase();
const failedDealbreakers = dealbreakers.filter(s => !resumeLower.includes(s));

return [{
  json: {
    resumeTextSanitized: upstreamContext.resumeTextSanitized || '',
    resumeText: upstreamContext.resumeText || '',
    scoringConfig: upstreamContext.scoringConfig || '',
    config: upstreamContext.config || {},
    weights: upstreamContext.weights || {},
    fileId: upstreamContext.fileId || '',
    fileName: upstreamContext.fileName || '',
    submissionDate: upstreamContext.submissionDate || '',
    confidencePenaltyFromExtraction: upstreamContext.confidencePenaltyFromExtraction || 0,
    confidenceSignals: upstreamContext.confidenceSignals || [],
    inferredFields: upstreamContext.inferredFields || '',
    resumeTruncated: upstreamContext.resumeTruncated || false,
    candidateName: candidateInfo.name || '',
    candidateEmail: candidateInfo.email || '',
    candidateMobile: candidateInfo.mobile || '',
    candidateCurrentTitle: candidateInfo.current_title || '',
    candidateId: candidateId || 'UNKNOWN',
    graduationYear: candidateInfo.graduation_year || '',
    isStudent: candidateInfo.is_student || '',
    dealBreakerFailed: failedDealbreakers.length > 0,
    failedDealbreakers: failedDealbreakers
  }
}];

const item = $input.item.json;

let scores = null;

try {
  const content = item.content;
  let rawText = Array.isArray(content)
    ? content.filter(c => c.type === 'text').map(c => c.text).join('')
    : JSON.stringify(content);
  const cleaned = rawText
    .replace(/```json/g, '').replace(/```/g, '').trim();
  scores = JSON.parse(cleaned);
} catch(e) {
  return [{
    json: {
      ...item,
      aiResponseError: true,
      processingStatus: 'AI_RESPONSE_ERROR',
      errorDetails: 'AI scoring failed to return valid JSON'
    }
  }];
}

// Clamp scores
const d1 = Math.min(10, Math.max(0, parseFloat(scores.d1_skills?.score) || 0));
const d2 = Math.min(10, Math.max(0, parseFloat(scores.d2_experience?.score) || 0));
const d3 = Math.min(10, Math.max(0, parseFloat(scores.d3_seniority?.score) || 0));
const d4 = Math.min(10, Math.max(0, parseFloat(scores.d4_impact?.score) || 0));
const rawD5 = parseFloat(scores.d5_red_flags?.score) || 0;
const d5 = Math.min(0, Math.max(-10, -rawD5));

// Weights
const w1 = parseFloat(item.config?.Weight_Skills_Match) || 35;
const w2 = parseFloat(item.config?.Weight_Experience) || 25;
const w3 = parseFloat(item.config?.Weight_Seniority) || 20;
const w4 = parseFloat(item.config?.Weight_Impact_Quality) || 15;
const w5 = parseFloat(item.config?.Weight_Red_Flag_Penalty) || 5;

// Weighted scores
const d1Weighted = Math.round((d1 * w1) / 100 * 10) / 10;
const d2Weighted = Math.round((d2 * w2) / 100 * 10) / 10;
const d3Weighted = Math.round((d3 * w3) / 100 * 10) / 10;
const d4Weighted = Math.round((d4 * w4) / 100 * 10) / 10;
const d5Weighted = Math.round((d5 * w5) / 100 * 10) / 10;

// Final score
let finalScore = ((d1 * w1) + (d2 * w2) + (d3 * w3) + (d4 * w4)) / 10;
finalScore = Math.max(0, Math.min(100, Math.round((finalScore + d5Weighted) * 10) / 10));

// Recommendation tier - HR friendly labels
let recommendationTier = 'Reject';
if (finalScore >= 80) recommendationTier = 'Strong Shortlist';
else if (finalScore >= 65) recommendationTier = 'Shortlist';  // ← both say Shortlist
else if (finalScore >= 50) recommendationTier = 'Maybe';

// Confidence
let evidencePenalty = 0;
const evidenceSignals = [];
if (!scores.d1_skills?.evidence || scores.d1_skills.evidence.length < 10) {
  evidencePenalty++; evidenceSignals.push('Skills scored without direct evidence');
}
if (!scores.d2_experience?.evidence || scores.d2_experience.evidence.length < 10) {
  evidencePenalty++; evidenceSignals.push('Experience scored without direct evidence');
}
if (!scores.d3_seniority?.evidence || scores.d3_seniority.evidence.length < 10) {
  evidencePenalty++; evidenceSignals.push('Seniority scored without direct evidence');
}
if (!scores.d4_impact?.evidence || scores.d4_impact.evidence.length < 10) {
  evidencePenalty++; evidenceSignals.push('Impact scored without direct evidence');
}

const totalPenalty = (item.confidencePenaltyFromExtraction || 0) + evidencePenalty;
const confidenceScore = Math.max(0, 10 - totalPenalty);
const confidenceLevel = confidenceScore >= 8 ? 'High' : confidenceScore >= 5 ? 'Medium' : 'Low';
const allSignals = [...(item.confidenceSignals || []), ...evidenceSignals];

// Skills formatting
const mustHaveConfirmed = (scores.d1_skills?.must_have_confirmed || []).join(', ');
const mustHaveInferred = (scores.d1_skills?.must_have_inferred || []).join(', ');
const mustHaveMissing = (scores.d1_skills?.must_have_missing || []).join(', ');
const niceToHaveConfirmed = (scores.d1_skills?.nice_to_have_confirmed || []).join(', ');
const niceToHaveInferred = (scores.d1_skills?.nice_to_have_inferred || []).join(', ');

// Skills gap summary
const missingCount = (scores.d1_skills?.must_have_missing || []).length;
const skillsGapSummary = missingCount > 0
  ? `${missingCount} missing: ${mustHaveMissing}`
  : 'All must-have skills present';

// Red flags as labels
const flagsList = scores.d5_red_flags?.flags || [];
const experienceRequired = item.config?.Experience_Required || '';
const totalYearsFound = scores.d2_experience?.total_years_found || '';

let redFlags = '';
if (flagsList.length > 0) {
  redFlags = flagsList.join(' | ');
} else {
  const notes = [];
  notes.push('No major red flags identified');
  if (d2 <= 7 && experienceRequired && totalYearsFound) {
    notes.push(`Experience: ${cleanTotalExperience} vs ${experienceRequired}`);
  }
  redFlags = notes.join(' — ');
}

// Summary reasoning
const summaryReasoning = scores.candidate_summary?.executive_summary || '';

// Experience and company
const totalExperience = scores.candidate_summary?.total_years_experience
  || scores.d2_experience?.total_years_found || '';
const currentCompany = scores.candidate_summary?.current_company || '';
const cleanTotalExperience = (totalExperience || '')
  .split(/[.—–\n]/)[0].trim().slice(0, 60);

const cleanDomainMatch = (scores.d2_experience?.domain_match || '')
  .split(/[.—–\n]/)[0].trim().slice(0, 80);

return [{
  json: {
    // Candidate info
    candidateName: item.candidateName || '',
    candidateEmail: item.candidateEmail || '',
    candidateMobile: item.candidateMobile || '',
    candidateCurrentTitle: item.candidateCurrentTitle || '',
    currentCompany: currentCompany,
    candidateId: item.candidateId || '',
    fileId: item.fileId || '',
    fileName: item.fileName || '',
    submissionDate: item.submissionDate || new Date().toISOString(),
    processingDate: new Date().toISOString(),
    config: item.config || {},
    inferredFields: item.inferredFields || '',
    resumeTruncated: item.resumeTruncated || false,
    confidenceSignals: allSignals.join(' | '),
    // Scores
    scores,
    d1Raw: d1, d1Weight: w1, d1Weighted,
    d2Raw: d2, d2Weight: w2, d2Weighted,
    d3Raw: d3, d3Weight: w3, d3Weighted,
    d4Raw: d4, d4Weight: w4, d4Weighted,
    d5Raw: d5, d5Weight: w5, d5Weighted,
    finalScore,
    finalScoreDisplay: `${finalScore} / 100`,
    recommendationTier,
    confidenceLevel,
    // HR friendly fields
    summaryReasoning,
    skillsGapSummary,
    mustHaveConfirmed,
    mustHaveInferred,
    mustHaveMissing,
    niceToHaveConfirmed,
    niceToHaveInferred,
    redFlags,
    d1Reasoning: scores.d1_skills?.reasoning || '',
    d2Reasoning: scores.d2_experience?.reasoning || '',
    d3Reasoning: scores.d3_seniority?.reasoning || '',
    d4Reasoning: scores.d4_impact?.reasoning || '',
    d5Reasoning: scores.d5_red_flags?.reasoning || '',
    keyEvidence: scores.key_evidence || '',
    totalExperience: cleanTotalExperience,
    domainMatch: cleanDomainMatch,
    processingStatus: 'SCORED',
    graduationYear: scores.candidate_summary?.graduation_year || '',
    isStudent: scores.candidate_summary?.is_student || '',
    internshipSummary: scores.d2_experience?.internship_summary || '',
    errorDetails: ''
  }
}];

const data = $input.item.json;

let status = 'ERROR';
let errorDetails = '';

if (data.isPDF === false) {
  status = 'NOT_PDF';
  errorDetails = `File rejected — not a PDF: ${data.fileName || data.name || 'unknown'}`;
} else if (data.isDuplicateFile === true) {
  status = 'DUPLICATE';
  errorDetails = `Already processed — file ID: ${data.fileId || data.id || ''}`;
} else if (data.readyToScore !== 'YES') {
  status = 'CONFIG_NOT_READY';
  errorDetails = 'Ready_To_Score is not YES in config sheet';
} else if (data.jdFound === false) {
  status = 'JD_NOT_FOUND';
  errorDetails = 'JD file not found — check JD_File_Name in config sheet';
} else if (data.proceedWithScoring === false) {
  status = 'JD_QUALITY_FAILED';
  errorDetails = `JD quality too low (${data.jdQualityScore}/10) — improve the JD`;
} else if (data.dealBreakerFailed) {
  status = 'HARD_DISQUALIFY';
  errorDetails = `Missing dealbreaker skills: ${(data.failedDealbreakers || []).join(', ')}`;
} else if (data.resumeExtractionFailed) {
  status = 'EXTRACTION_FAILED';
  errorDetails = 'Resume text could not be extracted reliably. Check PDF format.';
} else if (data.aiResponseError) {
  status = 'AI_RESPONSE_ERROR';
  errorDetails = data.errorDetails || 'AI scoring failed';
} else {
  status = 'ERROR';
  errorDetails = 'Unknown processing error';
}

return [{
  json: {
    candidateName: data.candidateName || '',
    candidateEmail: data.candidateEmail || '',
    candidateMobile: data.candidateMobile || '',
    fileName: data.fileName || data.name || '',
    fileId: data.fileId || data.id || '',
    submissionDate: data.submissionDate || new Date().toISOString(),
    processingStatus: status,
    errorDetails: errorDetails
  }
}];

const items = $input.all();
const item = items[0];

// Get resume text from direct input (Extract Resume Text2)
const resumeText = item.json.text || '';

// Get JD context - Parse JD Response1 is upstream
// on the same linear path through Update Config Row 2
const jdContext = $('Parse JD Response1').item.json;

return [{
  json: {
    resumeText: resumeText,
    config: jdContext.config || {},
    weights: jdContext.weights || {},
    extractedRoleName: jdContext.extractedRoleName || '',
    extractedSeniority: jdContext.extractedSeniority || '',
    extractedExperience: jdContext.extractedExperience || '',
    extractedIndustry: jdContext.extractedIndustry || '',
    extractedAdjacentIndustries: jdContext.extractedAdjacentIndustries || '',
    extractedResponsibilities: jdContext.extractedResponsibilities || '',
    extractedMustHaveSkills: jdContext.extractedMustHaveSkills || '',
    extractedNiceToHaveSkills: jdContext.extractedNiceToHaveSkills || '',
    inferredFields: jdContext.inferredFields || '',
    absentFields: jdContext.absentFields || ''
  }
}];
